import Foundation

public enum LogLevel: Int, Comparable, Sendable {
    case debug = 0, info, warning, error

    public static func < (lhs: LogLevel, rhs: LogLevel) -> Bool { lhs.rawValue < rhs.rawValue }

    var label: String {
        switch self {
        case .debug: "DEBUG"
        case .info: "INFO"
        case .warning: "WARN"
        case .error: "ERROR"
        }
    }

    public static func from(string: String) -> LogLevel {
        switch string.lowercased() {
        case "debug": .debug
        case "warning", "warn": .warning
        case "error": .error
        default: .info
        }
    }
}

public final class FileLogger: Sendable {
    public let filePath: String
    public let minLevel: LogLevel
    private let maxBytes: UInt64 = 5 * 1024 * 1024
    private let queue = DispatchQueue(label: "FileLogger.serialQueue")

    public init(filePath: String, minLevel: LogLevel = .info) {
        self.filePath = filePath
        self.minLevel = minLevel
        let dir = (filePath as NSString).deletingLastPathComponent
        do {
            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
        } catch {
            fputs("FileLogger: cannot create log directory \(dir): \(error)\n", stderr)
        }
    }

    public func log(_ level: LogLevel, _ message: String) {
        guard level >= minLevel else { return }
        append(level: level, message: message)
    }

    /// Blocks until all previously submitted log entries have been written to disk.
    /// Intended for tests that inspect log file contents after calling `log()`.
    func waitForPendingWrites() {
        queue.sync {}
    }

    // MARK: - Private

    private func append(level: LogLevel, message: String) {
        queue.async { [self] in
            // Per-call allocation — ISO8601DateFormatter is not thread-safe;
            // acceptable here because logging is a cold path
            let timestamp = ISO8601DateFormatter().string(from: Date())
            let entry = "[\(timestamp)] [\(level.label)] \(message)\n"
            guard let data = entry.data(using: .utf8) else { return }
            if !FileManager.default.fileExists(atPath: self.filePath) {
                FileManager.default.createFile(atPath: self.filePath, contents: nil)
            }

            self.rotateIfNeeded()

            guard let handle = FileHandle(forWritingAtPath: self.filePath) else { return }
            defer { handle.closeFile() }
            handle.seekToEndOfFile()
            handle.write(data)
        }
    }

    private func rotateIfNeeded() {
        guard let attrs = try? FileManager.default.attributesOfItem(atPath: filePath),
              let size = attrs[.size] as? UInt64,
              size > maxBytes else { return }
        let backup = filePath + ".1"
        try? FileManager.default.removeItem(atPath: backup)
        do {
            try FileManager.default.moveItem(atPath: filePath, toPath: backup)
        } catch {
            fputs("FileLogger: rotation failed for \(filePath): \(error)\n", stderr)
        }
        FileManager.default.createFile(atPath: filePath, contents: nil)
    }
}

// MARK: - Shared loggers

public enum Loggers {
    private static let cacheDir: String = {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        return "\(home)/.cache/ai-usages-tracker"
    }()

    private static let level: LogLevel = {
        LogLevel.from(string: ProcessInfo.processInfo.environment["AI_TRACKER_LOG_LEVEL"] ?? "info")
    }()

    public static let app = FileLogger(filePath: "\(cacheDir)/app.log", minLevel: level)
    public static let claude = FileLogger(filePath: "\(cacheDir)/claude-usages-connector.log", minLevel: level)
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("FileLogger")
struct FileLoggerTests {
    private func makeTempPath() -> String {
        NSTemporaryDirectory() + "ai-tracker-log-\(UUID().uuidString)/test.log"
    }

    @Test("creates directory and log file on first write")
    func createsFile() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.info, "hello")
        logger.waitForPendingWrites()
        #expect(FileManager.default.fileExists(atPath: path))
    }

    @Test("respects minimum log level")
    func respectsMinLevel() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .warning)
        logger.log(.debug, "should not appear")
        logger.log(.info, "should not appear")
        logger.log(.warning, "should appear")
        logger.waitForPendingWrites()
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(!content.contains("should not appear"))
        #expect(content.contains("should appear"))
    }

    @Test("log entry format contains timestamp and level")
    func logFormat() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.error, "test message")
        logger.waitForPendingWrites()
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(content.contains("[ERROR]"))
        #expect(content.contains("test message"))
        #expect(content.contains("[20")) // ISO8601 year prefix
    }

    @Test("LogLevel.from parses strings correctly")
    func logLevelFromString() {
        #expect(LogLevel.from(string: "debug") == .debug)
        #expect(LogLevel.from(string: "DEBUG") == .debug)
        #expect(LogLevel.from(string: "warning") == .warning)
        #expect(LogLevel.from(string: "warn") == .warning)
        #expect(LogLevel.from(string: "error") == .error)
        #expect(LogLevel.from(string: "info") == .info)
        #expect(LogLevel.from(string: "garbage") == .info)
    }

    @Test("LogLevel comparison works")
    func logLevelComparison() {
        #expect(LogLevel.debug < LogLevel.info)
        #expect(LogLevel.info < LogLevel.warning)
        #expect(LogLevel.warning < LogLevel.error)
    }

    @Test("log() is safe under 20 concurrent calls from a TaskGroup")
    func concurrentLogging() async {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        await withTaskGroup(of: Void.self) { group in
            for i in 0..<20 {
                group.addTask {
                    logger.log(.info, "message \(i)")
                }
            }
        }
        // Drain the serial queue: all async dispatches submitted before this point are done.
        logger.waitForPendingWrites()
        #expect(FileManager.default.fileExists(atPath: path))
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(!content.isEmpty)

        // Every line must start with a valid ISO8601 timestamp — verifies no
        // partial corruption under concurrent formatter usage.
        let formatter = ISO8601DateFormatter()
        let lines = content.split(separator: "\n")
        #expect(lines.count == 20)
        for line in lines {
            // Format: [2026-04-17T12:00:00Z] [INFO] message N
            guard let open = line.firstIndex(of: "["),
                  let close = line.firstIndex(of: "]") else {
                Issue.record("Missing timestamp brackets in: \(line)")
                continue
            }
            let timestamp = String(line[line.index(after: open)..<close])
            #expect(formatter.date(from: timestamp) != nil, "Invalid ISO8601 timestamp: \(timestamp)")
        }
    }

    @Test("rotates log file when exceeding max size")
    func rotatesFile() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        // Write > 5 MB to trigger rotation
        let bigMessage = String(repeating: "X", count: 10_000)
        for _ in 0..<600 {
            logger.log(.info, bigMessage)
        }
        logger.waitForPendingWrites()
        let backup = path + ".1"
        #expect(FileManager.default.fileExists(atPath: backup))
        // Main file should be smaller than backup after rotation
        let mainSize = (try? FileManager.default.attributesOfItem(atPath: path)[.size] as? UInt64) ?? 0
        #expect(mainSize < 5 * 1024 * 1024)
    }
}

import AppKit
import SwiftUI
import AIUsagesTrackersLib

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    private var poller: UsagePoller?
    private var accountMonitor: ClaudeActiveAccountMonitor?
    private var pidGuard: AppPidGuard?
    private var usageStore: UsageStore?
    private var refreshState: RefreshState?
    private var statusItem: NSStatusItem?
    private var popover: NSPopover?
    private var appearanceObserver: NSKeyValueObservation?

    func applicationDidFinishLaunching(_ notification: Notification) {
        NSApplication.shared.setActivationPolicy(.accessory)

        let home = FileManager.default.homeDirectoryForCurrentUser.path
        let guard_ = AppPidGuard(cacheDir: "\(home)/.cache/ai-usages-tracker")
        do {
            try guard_.acquire()
        } catch AppPidGuardError.alreadyRunning(let pid, _) {
            let alert = NSAlert()
            alert.messageText = "AI Usages Tracker is already running"
            alert.informativeText = "Another instance is active (PID \(pid)). Use the menu bar icon to quit it before launching a new one."
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        } catch {
            let alert = NSAlert()
            alert.messageText = "Failed to start AI Usages Tracker"
            alert.informativeText = error.localizedDescription
            alert.runModal()
            NSApplication.shared.terminate(nil)
            return
        }
        pidGuard = guard_

        let fileManager = UsagesFileManager.shared
        let refreshState = RefreshState()
        let poller = UsagePoller(
            connectors: [ClaudeCodeConnector()],
            fileManager: fileManager,
            refreshState: refreshState
        )
        let accountMonitor = ClaudeActiveAccountMonitor(
            fileManager: fileManager,
            onActiveAccountChanged: { [weak poller] _ in
                await poller?.pollOnce(force: true)
            }
        )
        self.poller = poller
        self.accountMonitor = accountMonitor
        self.refreshState = refreshState

        let usagesPath = fileManager.filePath
        let fileWatcher = UsagesFileWatcher(path: usagesPath)
        let store = UsageStore(fileWatcher: fileWatcher)
        self.usageStore = store

        setupStatusItem(store: store, refreshState: refreshState)
        trackStoreChanges(store: store)

        Task {
            store.start()
            await poller.start()
            await accountMonitor.start()
        }
    }

    func applicationWillTerminate(_ notification: Notification) {
        quit()
    }

    // MARK: - Status item

    private func setupStatusItem(store: UsageStore, refreshState: RefreshState) {
        let item = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        statusItem = item

        let popover = NSPopover()
        popover.behavior = .transient
        popover.contentSize = NSSize(width: 320, height: 400)
        popover.contentViewController = NSHostingController(
            rootView: UsageDetailsView(
                store: store,
                refreshState: refreshState,
                onRefresh: { [weak self] in
                    await self?.poller?.pollOnce(now: Date(), force: true)
                },
                onQuit: { [weak self] in
                    self?.quit()
                }
            )
        )
        self.popover = popover

        if let button = item.button {
            button.target = self
            button.action = #selector(togglePopover(_:))
            // The menu bar appearance can change (wallpaper-driven tinting) without
            // the app's effectiveAppearance changing, so we observe the button itself.
            appearanceObserver = button.observe(\.effectiveAppearance, options: [.new]) { [weak self] _, _ in
                Task { @MainActor in self?.refreshStatusItemImage() }
            }
        }

        refreshStatusItemImage()
    }

    private func refreshStatusItemImage() {
        guard let store = usageStore, let button = statusItem?.button else { return }
        let isDark = button.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let image = MenuBarLabelRenderer.render(
            segments: store.menuBarSegments,
            fallbackText: store.menuBarText,
            isDarkMenuBar: isDark
        )
        button.image = image
    }

    @objc private func togglePopover(_ sender: Any?) {
        guard let popover, let button = statusItem?.button else { return }
        if popover.isShown {
            popover.performClose(sender)
        } else {
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
            popover.contentViewController?.view.window?.makeKey()
        }
    }

    // MARK: - Observation

    /// Re-arms `withObservationTracking` after every change so the status item
    /// keeps mirroring the store. Tracking fires exactly once per registration.
    private func trackStoreChanges(store: UsageStore) {
        withObservationTracking {
            _ = store.menuBarSegments
            _ = store.menuBarText
        } onChange: { [weak self] in
            Task { @MainActor in
                guard let self, let store = self.usageStore else { return }
                self.refreshStatusItemImage()
                self.trackStoreChanges(store: store)
            }
        }
    }

    // MARK: - Quit

    private func quit() {
        let pollerRef = poller
        let monitorRef = accountMonitor
        Task {
            await pollerRef?.stop()
            await monitorRef?.stop()
        }
        usageStore?.stop()
        pidGuard?.release()
        NSApplication.shared.terminate(nil)
    }
}

