        let recent = ISO8601DateFormatter().string(from: Date())
        try "[\(recent)] [INFO] keep\n".data(using: .utf8)!.write(to: URL(fileURLWithPath: path))
        let backup = path + ".1"
        try "[\(old)] [INFO] discard\n".data(using: .utf8)!.write(to: URL(fileURLWithPath: backup))
